oxy_webhelp_navlinks = {"recover_gws_data-d30753e36617":{"topics":[{"title":"Recover Google Drive data","shortdesc":"<p class=\"shortdesc\">After <span class=\"ph\">RSC<\/span> protects your Google Drive workloads, you can recover         entire drives, or specific files and folders.<\/p>","href":"gws\/gdrive_recover_data.html","attributes":{"data-id":"gdrive_recover_data"},"menu":{"hasChildren":false},"tocID":"gdrive_recover_data-d30753e36631","next":"gdrive_recover_data-d30753e36631"},{"title":"Recover Gmail data","shortdesc":"<p class=\"shortdesc\"><span class=\"ph\">RSC<\/span> enables you to recover emails, calendar events, and contacts         from a point-in-time snapshot of a protected Google account.<\/p>","href":"gws\/gmail_recover_data.html","attributes":{"data-id":"gmail_recover_data"},"menu":{"hasChildren":false},"tocID":"gmail_recover_data-d30753e36706","next":"gmail_recover_data-d30753e36706"},{"title":"Google Workspace mass recovery","shortdesc":"<p class=\"shortdesc\">Mass recovery restores Google Drive data along with Gmail, Calendar, and Contacts         data from a point-in-time snapshot. Depending on the workload, mass recovery restores data         for multiple users, multiple shared drives, specific organizational units, or the entire         Google Workspace application.<\/p>","href":"gws\/gws_mass_recovery.html","attributes":{"data-id":"gws_mass_recovery"},"menu":{"hasChildren":false},"tocID":"gws_mass_recovery-d30753e36872","next":"gws_mass_recovery-d30753e36872"},{"title":"Google Workspace prioritized recovery","shortdesc":"<p class=\"shortdesc\">Prioritized recovery enables you to first restore high-priority data during a         recovery at the Organizational Unit (OU) or application level, before recovering the         remaining data.<\/p>","href":"gws\/gws_prioritized_recovery.html","attributes":{"data-id":"gws_prioritized_recovery"},"menu":{"hasChildren":false},"tocID":"gws_prioritized_recovery-d30753e36938","next":"gws_prioritized_recovery-d30753e36938"},{"title":"Google Workspace self-service recovery","shortdesc":"<p class=\"shortdesc\">Self-service recovery enables Google Workspace users to search for and recover their         own data without assistance from an administrator.<\/p>","href":"gws\/gws_self_service_recovery.html","attributes":{"data-id":"gws_self_service_recovery"},"menu":{"hasChildren":false},"tocID":"gws_self_service_recovery-d30753e36971","next":"gws_self_service_recovery-d30753e36971"},{"title":"Skipped items during Google Workspace backup","shortdesc":"<p class=\"shortdesc\"><span class=\"ph\">RSC<\/span> occasionally skips backing up some Google Workspace items due to         Google API errors or, in rare cases, internal errors.<\/p>","href":"gws\/gws_skipped_items_backup.html","attributes":{"data-id":"gws_skipped_items_backup"},"menu":{"hasChildren":false},"tocID":"gws_skipped_items_backup-d30753e37015","topics":[]}]}};